import{_ as r,o as i,c as t,ag as s}from"./chunks/framework.WmBmIPw-.js";const d=JSON.parse('{"title":"Clarke–Wright 节约算法（Savings, CVRP 经典构造）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristics/simple/clarke-wright-savings.md","filePath":"or-opt/heuristics/simple/clarke-wright-savings.md","lastUpdated":1777190173000}'),e={name:"or-opt/heuristics/simple/clarke-wright-savings.md"};function l(n,a,o,h,g,c){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="clarke–wright-节约算法-savings-cvrp-经典构造" tabindex="-1">Clarke–Wright 节约算法（Savings, CVRP 经典构造） <a class="header-anchor" href="#clarke–wright-节约算法-savings-cvrp-经典构造" aria-label="Permalink to &quot;Clarke–Wright 节约算法（Savings, CVRP 经典构造）&quot;">​</a></h1><p>Clarke 与 Wright（1964）为有容量的车辆路径（CVRP）提出：先令每客户各自由车场往返的小回路出发，再按「若把两客户接到同一条从车场出发的线路上能省多少路」的节约值 s 从大到小尝试合并路径，在容量等约束允许时把两条可对接的片段并成更长的一段，直至难以再合。是 <a href="./simple-heuristics.html">基础启发式</a> 中边合并系构造的代表；与 <a href="./insertion-heuristics.html">插入启发式</a> 逐步在弧上插客户的步态不同。见 <a href="./../heuristic-algorithms.html">启发式算法总览</a>。</p><hr><h2 id="节约量-savings" tabindex="-1">节约量（savings） <a class="header-anchor" href="#节约量-savings" aria-label="Permalink to &quot;节约量（savings）&quot;">​</a></h2><p>对车场编号 0、客户 i, j，对称路长 d、最小化总距时常写</p><p>[ s_{ij} = d_{0i} + d_{0j} - d_{ij}. ]</p><p><strong>含义</strong>：与「车场到 i 再回场、车场到 j 再回场、各为一条径向小回路」相比，若能把 i 与 j 在一条从车场出发的线路上接起来，i 与 j 间直连在路程上可少走的量。有载重、时间窗时实现里还须在合并前做可行检查。s_ij 大者一般先尝试；具体顺序与容量、车数、开闭路、有向/无向等规则一致。</p><hr><h2 id="并线的主要逻辑-思想性" tabindex="-1">并线的主要逻辑（思想性） <a class="header-anchor" href="#并线的主要逻辑-思想性" aria-label="Permalink to &quot;并线的主要逻辑（思想性）&quot;">​</a></h2><ul><li><strong>初始化</strong>：每客户单独成一条车场往返小回路。</li><li><strong>排序</strong>：算全体或剪枝后的 s_ij，按降序处理 (i, j) 对。</li><li><strong>典型迭代</strong>：对当前 s_ij 最大且可行情形的 (i, j)，若合并后仍满足载重等约束，且在有向/开闭路规则下端点可接，则并线；否则弃置本对。</li><li><strong>变体</strong>：并行 savings、串行合一条后重算、λ 与 μ 修正等，见所读文献与实现。</li></ul><p>有向网、多车场、时间窗时，能合并的可行性检查与有向/开闭路约定必须写清；上段不绑定到某一种伪代码，以免与实现细节矛盾。</p><hr><h2 id="性质与使用注意" tabindex="-1">性质与使用注意 <a class="header-anchor" href="#性质与使用注意" aria-label="Permalink to &quot;性质与使用注意&quot;">​</a></h2><ul><li><strong>不保证性</strong>：不保证 CVRP 全局最优，但常实现快、可与 <a href="./k-opt.html">k-opt 系列</a> 或元启发式衔接，或作初始上界。</li><li><strong>扩展性</strong>：有向、取送一体、多车场时，节约的写法与合并规则要随实例在可复现说明里定稿。</li></ul><p><strong>注</strong>：TSP 不是「仅车场 + 节约合并」CVRP 的直接子情形；本页以带车场的 CVRP 为主。车数有上界的问题里常可做类比，具体仍见所读文献。</p>',15)])])}const _=r(e,[["render",l]]);export{d as __pageData,_ as default};
